import React from 'react';
import {Alert, Button} from 'react-native';
import auth, {AuthSessionResult} from 'react-native-app-auth';

const config = {
  clientId: 'YOUR_CLIENT_ID', // Replace with your Client ID
  redirectUrl: 'YOUR_REDIRECT_URL', // Redirect Url after login
  scopes: ['openid', 'profile'], // Your required scopes for the app
  serviceConfiguration: {
    authorizationEndpoint: 'YOUR_AUTHORIZATION_ENDPOINT', // Authorization endpoint of OAuth server
    tokenEndpoint: 'YOUR_TOKEN_ENDPOINT' // Token endpoint of OAuth server
  }
};

class App extends React.Component {
  handleLogin = async () => {
    try {
      const result = await auth(config);
      
      if (result.type === 'success') {
        this.setState({accessToken: result.params.access_token});
      } else {
        throw new Error('No success');
      }
    } catch (error) {
      console.log(error);
    }
  };
  
  render() {
    return (
      <Button title="Login with OAuth" onPress={this.handleLogin} />
    );
  }
};

export default App;